/** 초상화 img 태그 반환 (base64가 비어있으면 이모지 폴백) */
function getPortraitHTML(classKey, size, extraClass) {
    // 남성 포트레이트 체크
    if (player && player.gender === "male" && CLASS_PORTRAITS_MALE && CLASS_PORTRAITS_MALE[classKey]) {
        size = size || 32;
        return '<img class="rpg-portrait ' + (extraClass||'') + '" src="' + CLASS_PORTRAITS_MALE[classKey] + '" width="' + size + '" height="' + size + '" style="image-rendering:pixelated;border-radius:' + (size>48?'12px':'8px') + ';border:2px solid rgba(255,215,0,0.3);" />';
    }
    size = size || 64;
    extraClass = extraClass || "";
    // 서큐버스 변신: 보호막 보유 시 정기충만 폼
    if (classKey === "succubus" && player && player.shield && player.shield > 0 && CLASS_PORTRAITS_FEMALE["succubus_powered"]) {
        classKey = "succubus_powered";
    }
    var src = CLASS_PORTRAITS_FEMALE[classKey];
    if (src && src.length > 10) {
        return '<img class="rpg-portrait ' + extraClass + '" src="' + src + '" width="' + size + '" height="' + size + '" alt="' + (PLAYER_CLASSES[classKey]?PLAYER_CLASSES[classKey].name:'') + '" />';
    }
    // 이미지가 없으면 이모지 폴백
    var cls = PLAYER_CLASSES[classKey];
    return '<div class="rpg-portrait rpg-portrait-emoji ' + extraClass + '" style="width:' + size + 'px;height:' + size + 'px;font-size:' + Math.round(size*0.6) + 'px;">' + (cls ? cls.icon : '❓') + '</div>';
}

