function getEquipCategory(item) {
    if (!item) return "weapon";
    var id = item.id || "";
    var name = item.name || "";
    var icon = item.icon || "";
    // 무기류
    if (/sword|blade|dagger|axe|mace|staff|bow|spear|club|hammer|rapier|fang|bane|reaver|cane/.test(id) || /검|칼|단검|도끼|철퇴|지팡이|활|창|곤봉|망치|레이피어|송곳니/.test(name)) return "weapon";
    // 방어구류
    if (/armor|mail|plate|robe|shield|helm|cap|boot|sandal|greave|cloak|cape|belt|fur|pelt|gauntlet|glove|circlet|crown|hat/.test(id) || /갑옷|로브|방패|투구|모자|장화|샌들|경갑|망토|벨트|가죽|건틀릿|장갑|서클릿|왕관/.test(name)) return "armor";
    // 마법/장신구류
    if (/ring|amulet|pendant|necklace|earring|bracelet|orb|tome|book|eye|stone|dice|feather|charm|clover/.test(id) || /반지|목걸이|펜던트|귀걸이|팔찌|구슬|마도서|서적|눈|결계석|주사위|깃털|부적|클로버|묵주/.test(name)) return "magic";
    return "weapon"; // default
}

