/** 몬스터 초상화 img/이모지 반환 */
function getEnemyPortraitHTML(enemyKey, size, extraClass) {
    size = size || 48;
    extraClass = extraClass || "";
    // 거울방 적: 플레이어 클래스 포트레이트 사용
    if (enemyKey && enemyKey.indexOf("mirror_") === 0) {
        var _mck = enemyKey.replace("mirror_", "");
        var _mSrc = (player && player.gender === "male" && CLASS_PORTRAITS_MALE && CLASS_PORTRAITS_MALE[_mck]) ? CLASS_PORTRAITS_MALE[_mck] : (CLASS_PORTRAITS_FEMALE[_mck] || null);
        if (_mSrc) {
            return '<img class="rpg-portrait rpg-portrait-enemy ' + extraClass + '" src="' + _mSrc + '" width="' + size + '" height="' + size + '" style="image-rendering:pixelated;border-radius:' + (size>48?'12px':'8px') + ';border:2px solid rgba(183,148,244,0.5);filter:hue-rotate(180deg) brightness(0.8);" />';
        }
    }
    // 드래곤 보스: DRAGON_BOSS_PORTRAITS에서 페이즈별 조회
    if (enemyKey && enemyKey.indexOf("dragon_") === 0 && typeof DRAGON_BOSS_PORTRAITS !== 'undefined') {
        var _drPhase = (currentEnemy && currentEnemy._dragonPhase === 2) ? "p2" : "p1";
        var _drKey = enemyKey + "_" + _drPhase;
        var _drSrc = DRAGON_BOSS_PORTRAITS[_drKey];
        if (_drSrc) {
            return '<img class="rpg-portrait rpg-portrait-enemy ' + extraClass + '" src="' + _drSrc + '" width="' + size + '" height="' + size + '" style="image-rendering:pixelated;border-radius:' + (size>48?'12px':'8px') + ';border:2px solid rgba(255,102,0,0.6);" />';
        }
    }
    var src = ENEMY_PORTRAITS[enemyKey];
    // 뱀파이어 남/여 — 전투 시작 시 결정된 값 사용
    if (enemyKey === "vampire" && ENEMY_PORTRAITS["vampire_m"]) {
        if (currentEnemy && currentEnemy._portraitVariant === "m") src = ENEMY_PORTRAITS["vampire_m"];
    }
    if (src && src.length > 10) {
        var tmpl = ENEMY_TEMPLATES[enemyKey];
        return '<img class="rpg-portrait rpg-portrait-enemy ' + extraClass + '" src="' + src + '" width="' + size + '" height="' + size + '" alt="' + (tmpl?tmpl.name:'') + '" style="border-color:rgba(229,62,62,0.5);" />';
    }
    // 이미지 없으면 기존 이모지
    var tmpl = ENEMY_TEMPLATES[enemyKey];
    return '<div class="rpg-portrait rpg-portrait-emoji rpg-portrait-enemy ' + extraClass + '" style="width:' + size + 'px;height:' + size + 'px;font-size:' + Math.round(size*0.55) + 'px;border-color:rgba(229,62,62,0.4);">' + (tmpl ? tmpl.icon : '❓') + '</div>';
}

/** 아이템(장비) 초상화 img/이모지 반환 */
function getEquipPortraitHTML(itemId, fallbackIcon, size, extraClass) {
    size = size || 32;
    extraClass = extraClass || "";
    // 전용 포트레이트 있으면 사용
    var src = EQUIP_PORTRAITS[itemId];
    if (src && src.length > 10) {
        return '<img class="rpg-portrait rpg-portrait-equip ' + extraClass + '" src="' + src + '" width="' + size + '" height="' + size + '" style="border-color:rgba(251,211,141,0.5);" />';
    }
    // 없으면 이모지 폴백
    return '<div class="rpg-portrait rpg-portrait-emoji rpg-portrait-equip ' + extraClass + '" style="width:' + size + 'px;height:' + size + 'px;font-size:' + Math.round(size*0.6) + 'px;border-color:rgba(251,211,141,0.3);">' + (fallbackIcon || '📦') + '</div>';
}

/** 스킬 초상화 img/이모지 반환 */
function getSkillPortraitHTML(skillKey, size, extraClass) {
    size = size || 24;
    extraClass = extraClass || "";
    var src = SKILL_PORTRAITS[skillKey];
    if (src && src.length > 10) {
        var def = SKILL_DEFS[skillKey];
        return '<img class="rpg-portrait rpg-portrait-skill ' + extraClass + '" src="' + src + '" width="' + size + '" height="' + size + '" style="border-color:rgba(255,215,0,0.4);border-radius:6px;max-width:' + size + 'px;max-height:' + size + 'px;" />';
    }
    // 이미지 없으면 null 반환 → 호출부에서 기존 이모지 사용
    return null;
}

