/** 스킬 태그 → CSS 클래스명 매핑 */
function _tagClass(tag) {
    var map = { "STR":"str", "DEX":"dex", "INT":"int", "WIS":"wis", "CON":"con", "CHA":"cha", "메인":"main",
        "낮은명중":"lowhit", "버프":"buff", "디버프":"debuff", "회복":"heal", "흡수":"drain",
        "자동명중":"autohit", "고정피해":"truedmg", "확정명중":"autohit", "턴소모없음":"freeturn" };
    return map[tag] || "default";
}

/** 몬스터 태그 → CSS 클래스명 매핑 */
function _enemyTagClass(tag) {
    var map = {
        "언데드":"undead", "야수":"beast", "벌레":"insect", "점액":"slime",
        "악마":"demon", "마법":"magic", "인형":"construct", "인간형":"humanoid",
        "파충류":"reptile", "용":"dragon", "영체":"spirit", "중장":"heavy",
        "암흑":"dark", "독":"poison", "변이":"mutant", "화염":"fire", "흡혈":"vampire"
    };
    return "enemy-" + (map[tag] || "default");
}

/** 몬스터 태그 뱃지 HTML 생성 */
function renderEnemyTags(tags) {
    if (!tags || tags.length === 0) return "";
    return '<div class="rpg-enemy-tags">' + tags.map(function(t) {
        return '<span class="rpg-enemy-tag rpg-enemy-tag-' + _enemyTagClass(t) + '">' + t + '</span>';
    }).join('') + '</div>';
}
