/** 등급 가중치를 고려하여 드롭 가능한 패시브 목록에서 가중 뽑기 (unique 제외) */
// ─── 스킬 등급별 가중 뽑기 ───
var SKILL_RARITY_WEIGHTS = { common:40, uncommon:30, rare:20, epic:10 };
function rollSkillByRarity(availableSkills) {
    if (!availableSkills || availableSkills.length === 0) return null;
    var weighted = availableSkills.map(function(sk) {
        var def = SKILL_DEFS[sk];
        var r = (def && def.rarity) ? def.rarity : "uncommon";
        var w = SKILL_RARITY_WEIGHTS[r] || 20;
        return { key:sk, weight:w };
    });
    var total = 0;
    for (var i=0;i<weighted.length;i++) total += weighted[i].weight;
    var roll = Math.random() * total;
    for (var i=0;i<weighted.length;i++) { roll -= weighted[i].weight; if (roll <= 0) return weighted[i].key; }
    return weighted[0].key;
}

function rollPassiveByRarity(availableKeys) {
    var droppable = availableKeys.filter(function(pk) {
        var def = PASSIVE_DEFS[pk];
        return def && def.rarity !== "unique" && def.rarity !== "legendary";
    });
    if (droppable.length === 0) return null;

    // 가중치 계산
    var weighted = droppable.map(function(pk) {
        var r = PASSIVE_DEFS[pk].rarity || "common";
        var w = PASSIVE_RARITIES[r] ? PASSIVE_RARITIES[r].weight : 10;
        return { key: pk, weight: w };
    });

    // 가중 뽑기
    var total = 0;
    for (var i = 0; i < weighted.length; i++) total += weighted[i].weight;
    var roll = Math.random() * total;
    var acc = 0;
    for (var i = 0; i < weighted.length; i++) {
        acc += weighted[i].weight;
        if (roll < acc) return weighted[i].key;
    }
    return weighted[weighted.length - 1].key;
}

/** 패시브 등급 색상 반환 */
function getPassiveRarityColor(pk) {
    var def = PASSIVE_DEFS[pk];
    if (!def) return "#a0aec0";
    var r = PASSIVE_RARITIES[def.rarity];
    return r ? r.color : "#a0aec0";
}

/** 패시브 등급 이름 반환 */
function getPassiveRarityName(pk) {
    var def = PASSIVE_DEFS[pk];
    if (!def) return "일반";
    var r = PASSIVE_RARITIES[def.rarity];
    return r ? r.name : "일반";
}

