/** 패시브 초상화 img/이모지 반환 */
function getPassivePortraitHTML(passiveKey, size, extraClass) {
    size = size || 28;
    extraClass = extraClass || "";
    var src = PASSIVE_PORTRAITS[passiveKey];
    if (src && src.length > 10) {
        var def = PASSIVE_DEFS[passiveKey];
        var rc = getPassiveRarityColor(passiveKey);
        return '<img class="rpg-portrait rpg-portrait-passive ' + extraClass + '" src="' + src + '" width="' + size + '" height="' + size + '" alt="' + (def ? def.name : '') + '" style="border-color:' + rc + ';max-width:' + size + 'px;max-height:' + size + 'px;" />';
    }
    // 이미지 없으면 null 반환 → 호출부에서 기존 이모지 사용
    return null;
}
