/** 희귀도에 따라 장비 아이템 뽑기 (floor에 따라 좋은 아이템 확률 증가) */
function rollEquipRarity(floor) { var _cyc=(gameState&&gameState.cycle)?gameState.cycle:0; floor=_cyc*10+floor;
    var rarities = ["common","uncommon","rare","epic","legendary"];
    var weights = [50, 30, 15, 4, 1];
    // 층 보너스: 높은 층일수록 높은 등급 확률 증가
    var floorBonus = Math.min(floor * 2, 20);
    weights[0] = Math.max(10, weights[0] - floorBonus);
    weights[1] += Math.floor(floorBonus * 0.3);
    weights[2] += Math.floor(floorBonus * 0.3);
    weights[3] += Math.floor(floorBonus * 0.25);
    weights[4] += Math.floor(floorBonus * 0.15);
    var total = 0; for (var i=0;i<weights.length;i++) total += weights[i];
    var r = Math.random() * total;
    for (var i=0;i<weights.length;i++) { r -= weights[i]; if (r <= 0) return rarities[i]; }
    return "common";
}

/** 랜덤 장비 드롭 (층 기반) */
function rollEquipDrop(floor) {
    var rarity = rollEquipRarity(floor);
    // 패시브: equipMaster — 장비 품질 1단계 상승
    if (hasPassive("equipMaster")) {
        var rarities = ["common","uncommon","rare","epic","legendary"];
        var idx = rarities.indexOf(rarity);
        if (idx >= 0 && idx < rarities.length - 1) rarity = rarities[idx + 1];
    }
    var pool = EQUIP_DB.filter(function(e){ return e.rarity === rarity; });
    if (pool.length === 0) pool = EQUIP_DB.filter(function(e){ return e.rarity === "common"; });
    return JSON.parse(JSON.stringify(pick(pool))); // deep copy
}

/** 인벤토리(배열)에서 장비 보너스 총합 계산 */
function calcEquipBonuses(inventory) {
    var bonuses = { str:0, dex:0, con:0, int:0, wis:0, cha:0 };
    if (!inventory || !Array.isArray(inventory)) return bonuses;
    for (var i = 0; i < inventory.length; i++) {
        var item = inventory[i];
        if (item && item.bonuses) {
            for (var stat in item.bonuses) {
                bonuses[stat] = (bonuses[stat] || 0) + item.bonuses[stat];
            }
        }
    }
    return bonuses;
}

/** 장비 보너스가 반영된 최종 능력치 (base + equip + passives) */
function getEffectiveAbilities() {
    var base = player.abilities;
    var eqBonus = calcEquipBonuses(player.equipment);
    var result = {};
    for (var k in base) {
        result[k] = base[k] + (eqBonus[k] || 0);
    }
    // 패시브: wisdomOfLife — 현재 HP 비율에 비례하여 WIS 증가 (최대+4)
    if (hasPassive("wisdomOfLife")) {
        var hpRatio = player.hp / player.maxHp;
        result.wis += Math.round(hpRatio * 4);
    }
    // 패시브: berserker — HP 50% 이하일 때 STR +4
    if (hasPassive("berserker") && player.hp <= player.maxHp * 0.5) {
        result.str += base.str*0.2;
    }
    // 버프: mutagen — 변이약 STR+4, DEX+4
    if (typeof playerBuff !== 'undefined' && playerBuff && playerBuff._mutagen > 0) { result.str += 4; result.dex += 4; }
    // 패시브: spiritAbsorb — 정기 흡수: 보호막 보유 시 전 능력치 +1
    if (hasPassive("spiritAbsorb") && player && player.shield && player.shield > 0) {
        for (var _spk in result) { result[_spk] += 1; }
    }
    return result;
}

/** 장비를 인벤토리에 추가 (배열에 push, 버리지 않음) */
function addEquipToInventory(item) {
    // 도감: 장비 등록
    if (item && item.id) registerCodex("equipment", item.id);
    if (!player.equipment || !Array.isArray(player.equipment)) player.equipment = [];
    // 패시브: pride — 오만: 비에픽/비전설이면 30% 에픽 변환, 에픽이면 5% 전설 변환
    if (hasPassive("pride") && item.rarity !== "mythic") {
        if (item.rarity !== "epic" && item.rarity !== "legendary" && Math.random() < 0.3) {
            // 에픽으로 변환
            var _ownedIds = {};
            if (player.equipment) { for (var _oi = 0; _oi < player.equipment.length; _oi++) _ownedIds[player.equipment[_oi].id] = true; }
            var epicPool = EQUIP_DB.filter(function(e){ return e.rarity === "epic" && !_ownedIds[e.id]; });
            if (epicPool.length === 0) epicPool = EQUIP_DB.filter(function(e){ return e.rarity === "epic"; });
            if (epicPool.length > 0) {
                item = JSON.parse(JSON.stringify(pick(epicPool)));
                if (item.id) registerCodex("equipment", item.id);
                addLog("👑 오만! 아이템이 에픽급으로 변환!", "level");
            }
        }
        if (item.rarity === "epic" && Math.random() < 0.05) {
            // 에픽 → 전설 변환
            var _ownedIds2 = {};
            if (player.equipment) { for (var _oi2 = 0; _oi2 < player.equipment.length; _oi2++) _ownedIds2[player.equipment[_oi2].id] = true; }
            var legendPool = EQUIP_DB.filter(function(e){ return e.rarity === "legendary" && !_ownedIds2[e.id]; });
            if (legendPool.length === 0) legendPool = EQUIP_DB.filter(function(e){ return e.rarity === "legendary"; });
            if (legendPool.length > 0) {
                item = JSON.parse(JSON.stringify(pick(legendPool)));
                if (item.id) registerCodex("equipment", item.id);
                addLog("👑✨ 오만의 극치! 전설급으로 승격!", "crit");
            }
        }
    }
    // 중복 장비 체크 — 같은 id면 새 장비를 자동 판매 (기존 유지)
    var _hasDup = false;
    for (var _di = 0; _di < player.equipment.length; _di++) {
        if (player.equipment[_di].id === item.id) { _hasDup = true; break; }
    }
    if (_hasDup) {
        var sellPrice = getItemSellPrice(item);
        player.gold += sellPrice;
        addLog("🔄 이미 보유 중! " + item.icon + " " + item.name + " → 자동 판매 +" + sellPrice + "G", "win");
        return;
    }
    player.equipment.push(item);
    recalcPlayerStats();
    var rarityInfo = EQUIP_RARITIES[item.rarity];
    addLog("✅ " + item.icon + " " + item.name + " (" + rarityInfo.name + ") 획득!", "win");
    // 여정 기록: 영웅급 이상 장비
    if (item.rarity === "epic" || item.rarity === "legendary" || item.rarity === "mythic") {
        _journeyLog.push({type:"equip", floor:gameState?gameState.floor:0, text:item.icon+" "+item.name+" ("+rarityInfo.name+") 획득!"});
    }

    // 전설급 장비: 유니크 패시브 자동 부여
    if (item.passive && PASSIVE_DEFS[item.passive]) {
        if (!player.passives) player.passives = [];
        if (player.passives.indexOf(item.passive) < 0) {
            player.passives.push(item.passive);
            var pDef = PASSIVE_DEFS[item.passive];
            var prc = getPassiveRarityColor(item.passive);
            addLog("🌟 전설 패시브 각성! <span style='color:" + prc + ";font-weight:bold;'>" + pDef.icon + " " + pDef.name + "</span> — " + pDef.desc, "level");
        } else {
            addLog("🌟 이미 보유한 전설 패시브: " + PASSIVE_DEFS[item.passive].name, "info");
        }
    }
}
