// ─── 퀘스트 이력 로드/저장 ───




async function loadAchievements() {
    try {
        var raw;
        if (_hasRisu) { raw = await Risuai.getArgument(ACHIEVEMENT_KEY); }
        else { raw = localStorage.getItem(ACHIEVEMENT_KEY); }
        if (raw) {
            var data = JSON.parse(raw);
            _achievements = data.unlocked || {};
            _achievementStats = data.stats || { kills:0, critsInBattle:0, poisonKills:0, consecutiveWins:0, classFloor5:{}, totalGames:0, totalDeaths:0, totalClears:0, totalGoldEarned:0, totalDamageDealt:0, totalDamageReceived:0, totalHealing:0, maxDamage:0, maxFloor:0, maxLevel:0, maxGold:0, bestCycleClass:null, bestCycle:0, classWins:{}, classBestFloor:{} };
        }
    } catch(e) { console.error("업적 로드 실패:", e); }
}

async function saveAchievements() {
    try {
        var data = JSON.stringify({ unlocked: _achievements, stats: _achievementStats });
        if (_hasRisu) { await Risuai.setArgument(ACHIEVEMENT_KEY, data); }
        else { localStorage.setItem(ACHIEVEMENT_KEY, data); }
    } catch(e) { console.warn("[RPG] error:", e); }
}

function unlockAchievement(key) {
    if (_achievements[key]) return; // 이미 해금
    var def = ACHIEVEMENTS[key];
    if (!def) return;
    _achievements[key] = Date.now();
    _achievementToast = def;
    addLog("🏆 업적 달성! " + def.icon + " " + def.name + " — " + def.desc, "level");
    saveAchievements();
    // 3초 후 토스트 제거
    setTimeout(function(){ _achievementToast = null; render(); }, 3000);
}

function checkAchievements() {
    if (!player || !gameState) return;
    // 층 도달
    if (gameState.floor >= 5) unlockAchievement("floor5");
    if (gameState.floor >= 10 && currentEnemy && currentEnemy.boss) unlockAchievement("floor10");
    // 레벨
    if (player.level >= 10) unlockAchievement("lv10");
    if (player.level >= 20) unlockAchievement("lv20");
    // 골드
    if (player.gold >= 1000) unlockAchievement("goldRich");
    // 주차
    if (gameState.cycle >= 1) unlockAchievement("cycle2");
    if (gameState.cycle >= 5) unlockAchievement("cycle5");
    // 장비 풀
    if (player.equipment && player.equipment.length >= 8) unlockAchievement("collector");
    // 연승
    if (_achievementStats.consecutiveWins >= 10) unlockAchievement("deathless10");
    // 처치수
    if (_achievementStats.kills >= 50) unlockAchievement("killCount50");
    if (_achievementStats.kills >= 200) unlockAchievement("killCount200");
    // 독 처치
    if (_achievementStats.poisonKills >= 10) unlockAchievement("poisonMaster");
    // 클래스별 5층
    if (player.classKey && gameState.floor >= 5) {
        _achievementStats.classFloor5[player.classKey] = true;
        if (Object.keys(_achievementStats.classFloor5).length >= 15) unlockAchievement("allClass");
    }
}

function renderAchievementToast() {
    if (!_achievementToast) return "";
    return '<div style="position:fixed;top:60px;left:50%;transform:translateX(-50%);background:linear-gradient(135deg,rgba(255,215,0,0.95),rgba(218,165,32,0.95));color:#1a1a2e;padding:12px 24px;border-radius:10px;box-shadow:0 4px 20px rgba(255,215,0,0.4);z-index:100002;font-size:14px;font-weight:bold;animation:rpg-toast-in 0.3s ease;pointer-events:none;text-align:center;">' +
        '<div>🏆 업적 달성!</div>' +
        '<div style="font-size:16px;margin:4px 0;">' + _achievementToast.icon + ' ' + _achievementToast.name + '</div>' +
        '<div style="font-size:11px;font-weight:normal;opacity:0.8;">' + _achievementToast.desc + '</div></div>';
}


