var _activeSynergies = [];

function checkSynergies() {
    _activeSynergies = [];
    if (!player || !player.passives) return;
    for (var i = 0; i < SYNERGIES.length; i++) {
        var syn = SYNERGIES[i];
        var req = syn.require;
        var met = true;
        // 패시브 체크
        for (var pi = 0; pi < req.passive.length; pi++) {
            if (player.passives.indexOf(req.passive[pi]) < 0) { met = false; break; }
        }
        if (!met) continue;
        // 장비 체크
        for (var ei = 0; ei < req.equip.length; ei++) {
            var found = false;
            if (player.equipment) {
                for (var j = 0; j < player.equipment.length; j++) {
                    if (player.equipment[j] && player.equipment[j].id === req.equip[ei]) { found = true; break; }
                }
            }
            if (!found) { met = false; break; }
        }
        if (met) _activeSynergies.push(syn);
    }
    return _activeSynergies;
}

function hasSynergy(effectId) {
    for (var i = 0; i < _activeSynergies.length; i++) {
        if (_activeSynergies[i].effect === effectId) return true;
    }
    return false;
}

function renderStatsPanel() {
    var s = _achievementStats;
    var classNames = {};
    for (var ck in PLAYER_CLASSES) classNames[ck] = PLAYER_CLASSES[ck].icon + " " + PLAYER_CLASSES[ck].name;
    
    var row = function(label, value, color) {
        return '<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid rgba(255,255,255,0.05);">' +
            '<span style="color:rgba(255,255,255,0.6);font-size:11px;">'+label+'</span>' +
            '<span style="color:'+(color||'#e2e8f0')+';font-size:12px;font-weight:bold;">'+value+'</span></div>';
    };
    
    // 클래스별 최고 층
    var classBest = '';
    if (s.classBestFloor) {
        var sorted = Object.keys(s.classBestFloor).sort(function(a,b){ return (s.classBestFloor[b]||0)-(s.classBestFloor[a]||0); });
        classBest = sorted.slice(0,5).map(function(ck){
            return '<span style="font-size:10px;color:rgba(255,255,255,0.5);">'+(classNames[ck]||ck)+' '+s.classBestFloor[ck]+'F</span>';
        }).join(' · ');
    }
    
    // 클래스별 클리어
    var classWinStr = '';
    if (s.classWins) {
        var sorted2 = Object.keys(s.classWins).sort(function(a,b){ return (s.classWins[b]||0)-(s.classWins[a]||0); });
        classWinStr = sorted2.map(function(ck){
            return '<span style="font-size:10px;color:#68d391;">'+(classNames[ck]||ck)+' ×'+s.classWins[ck]+'</span>';
        }).join(' · ');
    }
    
    return '<div style="padding:4px 0;">' +
        '<div style="text-align:center;font-size:15px;font-weight:bold;color:#90cdf4;margin-bottom:10px;">📊 모험 통계</div>' +
        '<div style="font-size:11px;color:#fbd38d;font-weight:bold;margin:8px 0 4px;">⚔️ 전투</div>' +
        row("총 처치수", (s.kills||0)+"마리", "#fc8181") +
        row("총 사망 횟수", (s.totalDeaths||0)+"회", "#fc8181") +
        row("총 게임 시작", (s.totalGames||0)+"회") +
        row("총 클리어", (s.totalClears||0)+"회", "#68d391") +
        row("최대 연승", (s.consecutiveWins||0)+"연승", "#fbd38d") +
        '<div style="font-size:11px;color:#fbd38d;font-weight:bold;margin:8px 0 4px;">💥 전투 수치</div>' +
        row("총 가한 피해", (s.totalDamageDealt||0).toLocaleString(), "#fc8181") +
        row("총 받은 피해", (s.totalDamageReceived||0).toLocaleString(), "#f6ad55") +
        row("총 회복량", (s.totalHealing||0).toLocaleString(), "#68d391") +
        row("최대 단일 피해", (s.maxDamage||0), "#ffd700") +
        '<div style="font-size:11px;color:#fbd38d;font-weight:bold;margin:8px 0 4px;">🏆 기록</div>' +
        row("최고 도달 층", (s.maxFloor||0)+"F", "#90cdf4") +
        row("최고 레벨", "Lv."+(s.maxLevel||0), "#c084fc") +
        row("최대 골드 보유", (s.maxGold||0)+"G", "#ffd700") +
        row("총 획득 골드", (s.totalGoldEarned||0).toLocaleString()+"G", "#ffd700") +
        row("독 처치", (s.poisonKills||0)+"마리", "#68d391") +
        (s.bestCycle > 0 ? row("최고 주차", (s.bestCycle||0)+"주차 ("+(classNames[s.bestCycleClass]||"?")+")", "#f687b3") : "") +
        (classBest ? '<div style="font-size:11px;color:#fbd38d;font-weight:bold;margin:8px 0 4px;">📋 클래스별 최고 층</div><div style="line-height:1.8;">'+classBest+'</div>' : '') +
        (classWinStr ? '<div style="font-size:11px;color:#fbd38d;font-weight:bold;margin:8px 0 4px;">🏅 클래스별 클리어</div><div style="line-height:1.8;">'+classWinStr+'</div>' : '') +
        '</div>';
}

function renderAchievementPanel() {
    var keys = Object.keys(ACHIEVEMENTS);
    var unlocked = Object.keys(_achievements).length;
    var total = keys.length;
    var cards = keys.map(function(k) {
        var def = ACHIEVEMENTS[k];
        var done = !!_achievements[k];
        if (!done && def.hidden) {
            return '<div style="padding:8px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);border-radius:6px;opacity:0.4;">' +
                '<span style="font-size:16px;">❓</span> <span style="color:rgba(255,255,255,0.3);font-size:11px;">숨겨진 업적</span></div>';
        }
        var bg = done ? 'rgba(255,215,0,0.1)' : 'rgba(255,255,255,0.03)';
        var border = done ? 'rgba(255,215,0,0.4)' : 'rgba(255,255,255,0.08)';
        var opacity = done ? '1' : '0.5';
        return '<div style="padding:8px;background:'+bg+';border:1px solid '+border+';border-radius:6px;opacity:'+opacity+';">' +
            '<span style="font-size:16px;">'+(done?def.icon:'🔒')+'</span> ' +
            '<span style="font-size:12px;font-weight:'+(done?'bold':'normal')+';color:'+(done?'#ffd700':'rgba(255,255,255,0.5)')+';">'+def.name+'</span>' +
            '<div style="font-size:10px;color:rgba(255,255,255,0.4);margin-top:2px;">'+def.desc+'</div>' +
            (done ? '<div style="font-size:8px;color:rgba(255,215,0,0.5);margin-top:2px;">✅ '+new Date(_achievements[k]).toLocaleDateString()+'</div>' : '') +
            '</div>';
    }).join("");
    return '<div style="padding:4px 0;">' +
        '<div style="text-align:center;margin-bottom:10px;">' +
        '<div style="font-size:15px;font-weight:bold;color:#ffd700;">🏆 업적 ('+unlocked+'/'+total+')</div>' +
        '<div style="background:rgba(255,255,255,0.1);border-radius:4px;height:6px;margin-top:6px;overflow:hidden;">' +
        '<div style="width:'+Math.round(unlocked/total*100)+'%;height:100%;background:linear-gradient(90deg,#ffd700,#f6ad55);border-radius:4px;"></div></div></div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">'+cards+'</div></div>';
}

/** 층에 따라 상인이 취급하는 포션 목록 */
function getAvailablePotions(floor) { var _cyc=(gameState&&gameState.cycle)?gameState.cycle:0; floor=_cyc*10+floor;
    if (floor <= 2) return ["potion_s"];
    if (floor <= 4) return ["potion_s","potion_m"];
    if (floor <= 6) return ["potion_s","potion_m","potion_l"];
    if (floor <= 8) return ["potion_m","potion_l","potion_x"];
    return ["potion_m","potion_l","potion_x","potion_full"];
}
/** 포션 사용 (종류 지정) — 회복량 반환 */
function usePotionByKey(potionKey) {
    var def = POTION_DEFS[potionKey]; if (!def) return 0;
    if (!player.potionInventory || !player.potionInventory[potionKey] || player.potionInventory[potionKey] <= 0) return 0;
    if (hasSynergy("phil_stone") && Math.random() < 0.5) { addLog("💎 현자의 돌! 포션이 보존됐다!", "buff"); } else { player.potionInventory[potionKey]--; }
    if (potionKey === "potion_full") {
        var heal = player.maxHp - player.hp;
        if (hasPassive("potionMaster")) heal = Math.round(heal * 1.5);
    if (hasPassive("chemMaster")) heal = Math.round(heal * 1.5);
        heal = applyHeal(heal);
        return heal;
    }
    var heal = rollDice(def.dice[0], def.dice[1], def.dice[2]);
    if (hasPassive("potionMaster")) { heal = Math.round(heal * 1.5); addLog("🧬 특이체질! 포션 회복 +50%", "buff"); }
    if (hasPassive("chemMaster")) { heal = Math.round(heal * 1.5); addLog("⚗️ 약제의 달인! 포션 효과 +50%", "buff"); }
    heal = applyHeal(heal);
    return heal;
}
/** 총 포션 보유 수 */
function totalPotionCount() {
    if (!player || !player.potionInventory) return player ? (player.potions || 0) : 0;
    var total = 0;
    for (var k in player.potionInventory) total += player.potionInventory[k];
    return total;
}
/** 레거시 potions → potionInventory 마이그레이션 */
function migratePotions() {
    if (player && !player.potionInventory) {
        player.potionInventory = {};
        if (player.potions && player.potions > 0) {
            player.potionInventory["potion_s"] = player.potions;
        }
        player.potions = 0;
    }
}

