function weightedPick(weights) {
    var total = 0;
    for (var i = 0; i < weights.length; i++) total += weights[i].weight;
    var r = Math.random() * total;
    for (var i = 0; i < weights.length; i++) {
        r -= weights[i].weight;
        if (r <= 0) return weights[i].type;
    }
    return weights[weights.length-1].type;
}

