// ※ API 3.0: 서버 저장 (세이브파일 동기화) — Risuai 없으면 localStorage 폴백
async function saveAll() { await slotSaveAll(); }
async function loadAll() {
    try {
        var p, s;
        if (_hasRisu) {
            p = await Risuai.getArgument(KEY_PLAYER);
            s = await Risuai.getArgument(KEY_STATE);
        } else {
            p = localStorage.getItem(KEY_PLAYER);
            s = localStorage.getItem(KEY_STATE);
        }
        if (p && s) {
            player = JSON.parse(p);
            gameState = JSON.parse(s);
            // 돌연변이 복원
            _slotMenuOpen = false;
        _playerMutations = (player && player.mutations) ? player.mutations : [];
            // 여정 로그 복원
            _journeyLog = (gameState && gameState._journeyLog) ? gameState._journeyLog : [];
            return true;
        }
    } catch(e) { console.error(PLUGIN_NAME, "로드 실패:", e); }
    return false;
}


// ═══════════════════════════════════════
//  캐릭터 슬롯 시스템 (5슬롯, 로그라이크식)
//  - 슬롯 = 캐릭터. 1슬롯 1캐릭터, 덮어쓰기 자동저장
//  - 수동 저장 없음. saveAll()이 활성 슬롯에 자동 기록
//  - 복사/다중저장 불가 (꼼수 방지)
// ═══════════════════════════════════════
var SLOT_COUNT = 5;
var _activeSlot = 0; // 0=슬롯 미선택(기존 호환), 1~5=활성 슬롯
function slotKey(n) { return "RISUlike_slot" + n; }

/** saveAll 래퍼: 활성 슬롯이 있으면 슬롯에도 동시 저장 */
var _origSaveAll = null; // 아래에서 덮어씀

async function slotSaveAll() {
    // 여정 로그를 gameState에 동기화
    if (gameState && _journeyLog) gameState._journeyLog = _journeyLog;
    // 기존 메인 세이브
    try {
        if (_hasRisu) {
            await Risuai.setArgument(KEY_PLAYER, JSON.stringify(player));
            await Risuai.setArgument(KEY_STATE, JSON.stringify(gameState));
        } else {
            localStorage.setItem(KEY_PLAYER, JSON.stringify(player));
            localStorage.setItem(KEY_STATE, JSON.stringify(gameState));
        }
    } catch(e) { console.error(PLUGIN_NAME, "저장 실패:", e); }
    // 활성 슬롯에도 덮어쓰기
    if (_activeSlot >= 1 && _activeSlot <= SLOT_COUNT && player && gameState) {
        try {
            var slotData = JSON.stringify({
                player: JSON.stringify(player),
                gameState: JSON.stringify(gameState),
                timestamp: Date.now(),
                summary: (DIFFICULTY_DEFS[gameDifficulty]?DIFFICULTY_DEFS[gameDifficulty].icon+" ":"") + player.icon + " " + player.name + " Lv." + player.level + " " + gameState.floor + "F"
            });
            if (_hasRisu) { await Risuai.setArgument(slotKey(_activeSlot), slotData); }
            else { localStorage.setItem(slotKey(_activeSlot), slotData); }
        } catch(e) { console.error(PLUGIN_NAME, "슬롯 저장 실패:", e); }
    }
}

async function loadFromSlot(n) {
    _slotMenuOpen = false;
    if (gameState && gameState.phase === "battle" && currentEnemy && currentEnemy.hp > 0) {
        showToast("⚔️ 전투 중에는 불러올 수 없습니다!"); return;
    }
    try {
        var raw;
        if (_hasRisu) { raw = await Risuai.getArgument(slotKey(n)); }
        else { raw = localStorage.getItem(slotKey(n)); }
        if (!raw) { showToast("빈 슬롯입니다!"); return; }
        var slotData = JSON.parse(raw);
        player = JSON.parse(slotData.player);
        _playerMutations = (player && player.mutations) ? player.mutations : [];
        gameState = JSON.parse(slotData.gameState);
        if (!player.equipment) player.equipment = [];
        if (!Array.isArray(player.equipment)) {
            var arr = []; for (var k in player.equipment) { if (player.equipment[k]) arr.push(player.equipment[k]); }
            player.equipment = arr;
        }
        if (!player.passives) player.passives = [];
        migratePotions();
        if (!gameState.totalTurns) gameState.totalTurns = 0;
        if (gameState.difficulty) gameDifficulty = gameState.difficulty;
        if (gameState.phase === "chooseDoor" && !gameState.doorChoices) gameState.doorChoices = generateDoorChoices();
        currentEnemy = null; battlePhase = "";
        // 여정 로그 복원
        _journeyLog = (gameState && gameState._journeyLog) ? gameState._journeyLog : [];
        // 전투 중이었으면 문 선택으로 되돌림
        if (gameState.phase === "battle") {
            gameState.phase = "chooseDoor";
            if (!gameState.doorChoices) gameState.doorChoices = generateDoorChoices();
            addLog("⚠️ 전투 중 중단됨 — 문 선택으로 돌아갑니다.", "info");
        }
        _activeSlot = n;
        await saveAll(); // 메인 세이브에도 반영
        showToast("📂 슬롯 " + n + " 불러오기!");
        // 모든 오버레이 닫기
        _slotMenuOpen = false; _slotFullPickMode = false; _showNewGameConfirm = false;
        _codexOpen = false; _graveyardOpen = false;
        _achievementOpen = false; _statsOpen = false;
        _transferMode = null; _transferCode = null;
        render();
    } catch(e) { showToast("로드 실패!"); console.error(e); }
}

async function deleteSlot(n) {
    try {
        if (_hasRisu) { await Risuai.setArgument(slotKey(n), ""); }
        else { localStorage.removeItem(slotKey(n)); }
        // 삭제한 슬롯이 현재 활성 슬롯이면 비활성화
        if (_activeSlot === n) { _activeSlot = 0; player = null; gameState = null; }
        showToast("🗑️ 슬롯 " + n + " 삭제!");
        _slotConfirmDelete = null; _slotMenuOpen = true; render();
    } catch(e) { showToast("삭제 실패!"); }
}

/** 새 게임을 특정 슬롯에 시작 */
function startNewGameInSlot(n) {
    _activeSlot = n;
    _slotMenuOpen = false;
    startNewGame(); // 기존 새 게임 → 난이도/클래스 선택 진입
}

async function getSlotSummaries() {
    var summaries = [];
    for (var i = 1; i <= SLOT_COUNT; i++) {
        try {
            var raw;
            if (_hasRisu) { raw = await Risuai.getArgument(slotKey(i)); }
            else { raw = localStorage.getItem(slotKey(i)); }
            if (raw) {
                var d = JSON.parse(raw);
                var date = new Date(d.timestamp);
                var dateStr = (date.getMonth()+1) + "/" + date.getDate() + " " + String(date.getHours()).padStart(2,"0") + ":" + String(date.getMinutes()).padStart(2,"0");
                // 난이도 텍스트 동적 생성
                var _diffText = "";
                try {
                    var _sg = JSON.parse(d.gameState);
                    if (_sg.difficulty && DIFFICULTY_DEFS[_sg.difficulty]) _diffText = "[" + DIFFICULTY_DEFS[_sg.difficulty].name + "] ";
                } catch(e2) {}
                var _baseSummary = d.summary || "???";
                summaries.push({ slot: i, summary: _diffText + _baseSummary, date: dateStr, hasData: true });
            } else {
                summaries.push({ slot: i, summary: null, date: null, hasData: false });
            }
        } catch(e) { summaries.push({ slot: i, summary: null, date: null, hasData: false }); }
    }
    return summaries;
}

