//  이전 코드 (Export / Import) — 활성 슬롯 연동
// ═══════════════════════════════════════

// UTF-8 안전 Base64 인코딩/디코딩 (TextEncoder/Decoder 기반, 폴백 포함)
function utf8ToBase64(str) {
    try {
        var bytes = new TextEncoder().encode(str);
        var binary = '';
        for (var i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
        return btoa(binary);
    } catch(e) {
        // 폴백: 기존 방식
        return btoa(unescape(encodeURIComponent(str)));
    }
}
function base64ToUtf8(b64) {
    try {
        var binary = atob(b64);
        var bytes = new Uint8Array(binary.length);
        for (var i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
        return new TextDecoder().decode(bytes);
    } catch(e) {
        // 폴백: 기존 방식 (이전 버전 세이브 코드 호환)
        return decodeURIComponent(escape(atob(b64)));
    }
}

function exportSaveCode() {
    // 모든 슬롯 데이터를 한번에 내보내기
    (async function(){
        try {
            var allSlots = {};
            for (var si = 1; si <= SLOT_COUNT; si++) {
                var raw;
                if (_hasRisu) { raw = await Risuai.getArgument(slotKey(si)); }
                else { raw = localStorage.getItem(slotKey(si)); }
                if (raw) {
                    var sd = JSON.parse(raw);
                    allSlots[si] = { p: JSON.parse(sd.player), g: JSON.parse(sd.gameState) };
                }
            }
            if (Object.keys(allSlots).length === 0) { showToast("저장된 슬롯이 없습니다!"); return; }
            var payload = JSON.stringify({ slots: allSlots, v: 2, achievements: _achievements, stats: _achievementStats, graveyard: _graveyard, codex: _codex });
            _transferCode = utf8ToBase64(payload);
            _transferMode = "export";
            render();
        } catch(e) { showToast("내보내기 실패!"); console.error(e); }
    })();
}

async function importSaveCode(code) {
    try {
        code = code.trim().replace(/\s+/g, '');
        var json = base64ToUtf8(code);
        var data = JSON.parse(json);
        
        // v2: 전체 슬롯 불러오기
        if (data.v === 2 && data.slots) {
            try {
                var count = 0;
                for (var si in data.slots) {
                    var sd = data.slots[si];
                    if (!sd.p || !sd.g) continue;
                    var slotData = JSON.stringify({
                        player: JSON.stringify(sd.p),
                        gameState: JSON.stringify(sd.g),
                        timestamp: Date.now(),
                        summary: (sd.g.difficulty&&DIFFICULTY_DEFS[sd.g.difficulty]?DIFFICULTY_DEFS[sd.g.difficulty].icon+" ":"") + sd.p.icon + " " + sd.p.name + " Lv." + sd.p.level + " " + (sd.g.floor||1) + "F"
                    });
                    if (_hasRisu) { await Risuai.setArgument(slotKey(Number(si)), slotData); }
                    else { localStorage.setItem(slotKey(Number(si)), slotData); }
                    count++;
                }
                // 업적/통계 복원
                if (data.achievements) { _achievements = data.achievements; }
                if (data.stats) { _achievementStats = data.stats; }
                // 묘지 복원
                if (data.graveyard && Array.isArray(data.graveyard)) { _graveyard = data.graveyard; await saveGraveyard(); }
                // 도감 복원
                if (data.codex) { _codex = data.codex; await saveCodex(); }
                await saveAchievements();
                // 첫 번째 슬롯 자동 로드
                _activeSlot = 1;
                if (await loadFromSlot(1)) {
                    migratePotions();
                }
                showToast("✅ " + count + "개 슬롯 + 업적 + 묘지 + 도감 불러오기 성공!");
            } catch(ie) { 
                console.error("[RPG] import v2 error:", ie); 
                showToast("⚠️ 불러오기 중 일부 오류 발생"); 
            }
            // 메인화면으로
            player = null; gameState = null; currentEnemy = null; battlePhase = "";
            _transferMode = null; _transferCode = null; 
            _statsOpen = false; _achievementOpen = false; _slotMenuOpen = false; _graveyardOpen = false; _codexOpen = false;
            render();
            return;
        }
        
        // v1 호환: 단일 세이브
        if (data.p && data.g) {
            player = data.p;
            gameState = data.g;
            if (!player.equipment) player.equipment = [];
            if (!Array.isArray(player.equipment)) {
                var arr = []; for (var k in player.equipment) { if (player.equipment[k]) arr.push(player.equipment[k]); }
                player.equipment = arr;
            }
            if (!player.passives) player.passives = [];
            migratePotions();
            if (!gameState.totalTurns) gameState.totalTurns = 0;
            if (gameState.difficulty) gameDifficulty = gameState.difficulty;
            if (gameState.phase === "chooseDoor" && !gameState.doorChoices) gameState.doorChoices = generateDoorChoices();
            currentEnemy = null; battlePhase = "";
            _activeSlot = 1;
            saveAll();
            showToast("✅ 불러오기 성공! (슬롯 1에 저장됨)");
            // 메인화면으로
            player = null; gameState = null; currentEnemy = null; battlePhase = "";
            _transferMode = null; _transferCode = null;
            _statsOpen = false; _achievementOpen = false; _slotMenuOpen = false; _graveyardOpen = false; _codexOpen = false;
            render();
            return;
        }
        
        showToast("❌ 잘못된 코드!");
        _transferMode = null; _transferCode = null; render();
    } catch(e) { showToast("❌ 코드 파싱 실패!"); console.error(e); _transferMode = null; _transferCode = null; render(); }
}

