// ═══════════════════════════════════════
//  플레이어 생성
// ═══════════════════════════════════════
function createPlayer(classKey) {
    var cls = PLAYER_CLASSES[classKey];
    var ab = {}; for(var k in cls.baseAbilities) ab[k]=cls.baseAbilities[k];
    var maxHp = cls.hitDie + mod(ab.con);
    var baseAC = 10 + Math.min(mod(ab.dex), cls.maxDexBonus !== undefined ? cls.maxDexBonus : 99) + cls.armorBonus;
    var profBonus = 2;
    var _atkMap = {warrior:"str",mage:"int",cleric:"wis",rogue:"dex",hunter:"dex",dhampir:"cha",paladin:"str",druid:"wis",berserker:"str",madman:"cha",bard:"cha",princess:"cha",necro:"int",monk:"dex",alchemist:"int",succubus:"cha"};
    var attackAbility = _atkMap[classKey] || "str";
    var p = {
        name:cls.name, classKey:classKey, icon:cls.icon,
        level:1, exp:0, expNext:100,
        abilities:ab,
        hp:maxHp, maxHp:maxHp,
        baseAC:baseAC,
        hitMod: mod(ab[attackAbility]) + profBonus,
        profBonus:profBonus,
        attackAbility:attackAbility,
        gold:0, potions:0, potionInventory:{ potion_s:3 },
        isDefending:false,
        killCount:0, floorCleared:0,
        skills: cls.skills.slice(),
        // 도감: 시작 스킬 등록
        extraSkills: [],
        equipment: [],  // 장비 인벤토리 (배열, 들어있는 모든 장비 능력치 반영)
        shield: 0,     // 보호막 (전투 중 임시 체력, 전투 종료 시 사라짐)
        passives: cls.startPassive ? [cls.startPassive] : [],   // 클래스 고유 패시브 포함
    };
    // ─── 직업 시작 장비 지급 ───
    if (cls.startEquip && cls.startEquip.length > 0) {
        var _legendPool = EQUIP_DB.filter(function(e){ return e.rarity === "legendary"; });
        for (var sei = 0; sei < cls.startEquip.length; sei++) {
            var seId = cls.startEquip[sei];
            var seItem = null;
            if (seId === "_random_legendary_" && _legendPool.length > 0) {
                var _ri = Math.floor(Math.random() * _legendPool.length);
                seItem = JSON.parse(JSON.stringify(_legendPool[_ri]));
                _legendPool.splice(_ri, 1);
                if (seItem.passive && PASSIVE_DEFS[seItem.passive] && p.passives.indexOf(seItem.passive) < 0) {
                    p.passives.push(seItem.passive);
                }
            } else {
                for (var sej = 0; sej < EQUIP_DB.length; sej++) {
                    if (EQUIP_DB[sej].id === seId) { seItem = JSON.parse(JSON.stringify(EQUIP_DB[sej])); break; }
                }
            }
            if (seItem) p.equipment.push(seItem);
        }
    }
    return p;
}
/** 패시브 보유 여부 체크 */
function hasPassive(key) { return player && player.passives && player.passives.indexOf(key) >= 0; }

// ═══════════════════════════════════════
//  게임 상태 초기화
// ═══════════════════════════════════════
function createGameState() {
    // 기존 데이터 보존 (2회차 유지)
    var _prevCompleted = (typeof gameState !== "undefined" && gameState && gameState.questsCompleted) ? gameState.questsCompleted.slice() : [];
    var _prevAlly = (typeof gameState !== "undefined" && gameState && gameState.ally) ? JSON.parse(JSON.stringify(gameState.ally)) : null;
    return {
        floor:1, progress:0, cycle:0, infiniteMode:false,
        difficulty: gameDifficulty,  // 난이도 저장
        totalTurns:0,          // 방 진입 횟수 (글로벌 스케일링 기준)
        phase:"chooseDoor",    // "chooseDoor" | "event" | "battle" | "boss" | "bossCleared"
        doorChoices: null,
        currentDoor: null,
        currentEvent: null,
        chestState: null,      // null | "pending" | "opened" | "mimic"
        shrineResult: null,
        blessingChoices: null,
        passiveChoices: null,
        blessingRewards: null,  // 축복 3선택지 [{type:"passive"|"gold"|"stat", ...}]
        merchantOffers: null,   // 상인 상품 배열
        forgeState: null,       // null | "pending" | "done"
        forgeResult: null,      // 용광로 결과 {success, item, newItem}
        darkContractChoices: null, // 어둠의 계약 3선택지
        quest: null,               // 미니퀘스트 {id, stage, choices:{}, flags:{}, nextFloor, active}
        ally: null,                // 전투 동료 {id, name, icon, triggerRate, effect, power, dialogue:[]}
        questsCompleted: [],       // 이번 런에서 완료된 퀘스트 ID 목록
        _assignedQuest: null,  // 이번 런에 배정된 퀘스트 ID (null이면 미등장)
        log:[], running:true,
        questsCompleted: _prevCompleted,  // 2회차 유지
        ally: _prevAlly,                   // 영구 동료 유지
    };
}

// ─── 방 3개 선택지 생성 ───
function generateDoorChoices() {
    var doorWeights = [
        {type:"dark",weight:12}, {type:"door",weight:15}, {type:"maze",weight:8},
        {type:"barrier",weight:8}, {type:"poison",weight:8}, {type:"wide",weight:8},
        {type:"narrow",weight:8}, {type:"magi",weight:4}, {type:"timewarp",weight:3},
        {type:"forge_room",weight:1}, {type:"treasure",weight:4}, {type:"cursed",weight:1},
        {type:"trial",weight:4}, {type:"library",weight:4}, {type:"gambling",weight:4},
        {type:"mirror",weight:2},
    ];
    // 천상의 대장간: 50% 확률로 풀에 추가 (실질 ~0.5%)
    if (Math.random() < 0.5) doorWeights.push({type:"celestial_forge",weight:1});
    // 전설의 제단: 25% 확률로 풀에 추가 (실질 ~0.25%)
    if (Math.random() < 0.25) doorWeights.push({type:"legend_altar",weight:1});
    // 보스전 직전이면 결계(safe) 방 제외
    if (gameState && gameState.progress >= PROGRESS_MAX) {
        doorWeights = doorWeights.filter(function(w){ return w.type !== "barrier"; });
    }
    var count = rnd(1, 3);
    var choices = [];
    for (var i = 0; i < count; i++) {
        choices.push(weightedPick(doorWeights));
    }
    // 용의 둥지: 각 층 7~9칸에 강제 1개 추가 (해당 주차의 해당 층에서 클리어하지 않았다면)
    if (gameState) {
        if (!gameState._dragonNestClearedFloors) gameState._dragonNestClearedFloors = {};
        var _dnKey = (gameState.cycle||0) + "_" + gameState.floor;
        if (!gameState._dragonNestClearedFloors[_dnKey]) {
            var prog = gameState.progress || 0;
            var _dnTargetFloor = gameState.floor;
            // 10층은 방 선택지에 넣지 않음 (강제 난입으로 처리)
            if (_dnTargetFloor !== 10 && prog >= 6 && prog <= 8) {
                if (choices.indexOf("dragon_nest") < 0) {
                    choices.push("dragon_nest");
                }
            }
        }
    }
    return choices;
}

