var QUEST_DEFS = {
    lilith: {
        name: "마족 소녀 리리스", icon: "🦇", minFloor: 1, maxStartFloor: 2,
        stages: [
            { floor:[1,2], event:"quest_dg_meet" },
            { floor:[3,4], event:"quest_dg_treasure" },
            { floor:[5,6], event:"quest_dg_crisis" },
            { floor:[9,9], event:"quest_dg_final" },
        ]
    },
};

// ─── 퀘스트 이벤트 훅: 현재 층에서 퀘스트 이벤트가 있는지 체크 ───
function checkQuestEvent() {
    if (!gameState) return null;
    var q = gameState.quest;
    var floor = gameState.floor;

    // 2주차 이후 리리스 퀘스트 비활성화
    if (q && q.id === "lilith" && gameState.cycle && gameState.cycle > 0) return null;

    // 퀘스트 진행 중이면 해당 스테이지 이벤트 체크 (50% 확률)
    if (q && q.active && q.id) {
        var def = QUEST_DEFS[q.id];
        if (!def || q.stage >= def.stages.length) return null;
        var stg = def.stages[q.stage];
        if (floor >= stg.floor[0] && floor <= stg.floor[1]) {
            return stg.event; // 퀘스트 이벤트는 해당 층에서 무조건 발동
        }
        if (floor > stg.floor[1] && q.stage < def.stages.length - 1) {
            q.stage++;
            return checkQuestEvent();
        }
        return null;
    }

    // 이번 런에 퀘스트 미배정이면 스킵
    if (!gameState._assignedQuest) return null;

    // 퀘스트 없으면 배정된 퀘스트 조우 체크
    if (!q) {
        var qid = gameState._assignedQuest;
        var completed = gameState.questsCompleted || [];
        if (completed.indexOf(qid) >= 0) return null;
        var d = QUEST_DEFS[qid];
        if (!d) return null;
        if (floor >= d.minFloor && floor <= d.maxStartFloor) {
            // 해당 층 범위 내에서 30% 확률로 조우
            return d.stages[0].event;
        }
    }
    return null;
}

// ─── 퀘스트 시작 ───
function startQuest(questId) {

    gameState.quest = {
        id: questId,
        stage: 1, // 0=만남(완료), 1=다음 스테이지부터
        choices: { kindness:0, greed:0, success:0, fail:0, invested:0 },
        flags: {},
        active: true
    };
    addLog("📜 퀘스트 시작: " + QUEST_DEFS[questId].icon + " " + QUEST_DEFS[questId].name, "level");
    saveAll();
}

// ─── 퀘스트 스테이지 진행 ───
function advanceQuest() {
    if (!gameState.quest || !gameState.quest.active) return;
    gameState.quest.stage++;
    var def = QUEST_DEFS[gameState.quest.id];
    if (gameState.quest.stage >= def.stages.length) {
        // 마지막 스테이지 도달 — 완료 처리는 해당 이벤트에서
    }
    saveAll();
}

// ─── 퀘스트 완료 ───
function completeQuest(reward) {
    if (!gameState.quest) return;
    var qid = gameState.quest.id;
    addLog("✅ 퀘스트 완료: " + QUEST_DEFS[qid].icon + " " + QUEST_DEFS[qid].name, "level");
    if (!gameState.questsCompleted) gameState.questsCompleted = [];
    gameState.questsCompleted.push(qid);
    gameState.quest.active = false;
    // 동료 보상이 있으면 설정
    if (reward && reward.ally) {
        gameState.ally = reward.ally;
        addLog("🤝 " + reward.ally.icon + " " + reward.ally.name + " 이(가) 동료가 되었다!", "level");
    }
    saveAll();
}

