function determineEvent(doorType) {
    var dt = DOOR_TYPES[doorType];
    // ─── 특수 문 효과 (최우선 — 문 선택해서 들어온 것) ───
    if (dt.effect === "safe") {
        return weightedPick(EVENT_WEIGHTS_SAFE);
    }
    if (dt.effect === "forge_guaranteed") return "forge";
    if (dt.effect === "celestial_forge") return "celestialForge";
    if (dt.effect === "legend_altar") return "legendaryBlessing";
    if (dt.effect === "dragon_nest") return "dragonNest";
    if (dt.effect === "treasure_room") return Math.random() < 0.5 ? "chest" : "merchant";
    if (dt.effect === "cursed_room") return "darkContract";
    if (dt.effect === "mirror_room") return "mirrorRoom";
    if (dt.effect === "trial_room") return "elite";
    if (dt.effect === "library_room") return Math.random() < 0.6 ? "blessing" : "shrine";
    if (dt.effect === "gambling_room") return "gambling";

    // ─── 미니 퀘스트 이벤트 체크 ───
    var questEvent = checkQuestEvent();
    if (questEvent) return questEvent;
    // 마기충만 방: 몬스터/엘리트 출현 확률 대폭 증가
    if (dt.effect === "magi_room") {
        var magiWeights = EVENT_WEIGHTS_NORMAL.map(function(w) {
            if (w.type === "monster") return { type:"monster", weight: w.weight * 3 };
            if (w.type === "elite") return { type:"elite", weight: 30 };
            return { type:w.type, weight: Math.max(1, Math.floor(w.weight * 0.3)) };
        });
        return weightedPick(magiWeights);
    }
    // 층에 따라 엘리트 가중치 조정 (초반에는 엘리트가 거의 안 나옴)
    var floor = getEffectiveFloor();
    var eliteWeight = floor <= 2 ? 3 : floor <= 4 ? 6 : floor <= 7 ? 10 : 15;
    var adjusted = EVENT_WEIGHTS_NORMAL.map(function(w) {
        if (w.type === "elite") return { type:"elite", weight: eliteWeight };
        return { type:w.type, weight:w.weight };
    });
    // 패시브: treasureHunt — 상자 발견 확률 증가
    if (hasPassive("treasureHunt")) {
        adjusted = adjusted.map(function(w) {
            return { type:w.type, weight: w.type === "chest" ? w.weight * 2.5 : w.weight };
        });
    }
    return weightedPick(adjusted);
}

// ─── 적 스폰 ───
function spawnEnemy(key, floor) {
    var tmpl = ENEMY_TEMPLATES[key];
    var _cycle = (gameState && gameState.cycle) ? gameState.cycle : 0;
    var effectiveFloor = _cycle * 10 + floor; // 2주차 1층 = 11, 3주차 1층 = 21
    var scale = 1 + (effectiveFloor - 1) * 0.10;
    // 글로벌 턴 기반 추가 스케일링 (방 진입 횟수 기반)
    var turns = (gameState && gameState.totalTurns) ? gameState.totalTurns : 0;
    var diff = getDifficulty();
    var turnScale = 1 + turns * 0.022 * diff.turnScaleMul;        // 난이도별 HP 턴 스케일 (강화)
    var turnAC    = Math.floor(turns * 0.10);                       // AC 성장 (원본 복원)
    var turnHit   = Math.floor(turns * 0.07);                       // 명중 성장 (완화)
    var turnDmg   = Math.floor(turns * 0.09);                       // 피해 성장 (완화)
    var turnDmgScale = Math.min(1.80, 1 + turns * 0.014);          // 피해 배율 (캡 1.80, 57방 도달)
    // 주회차 추가 보정
    var cycleMul = 1 + _cycle * 0.3; // 주회차당 HP ×1.3
    var cycleAC = _cycle * 2;
    var cycleHit = _cycle * 2;
    var cycleDmg = _cycle * 3;
    var ab = {}; for(var k in tmpl.abilities) ab[k]=tmpl.abilities[k];
    var dd = tmpl.dmgDice.slice(); // 복사
    dd[2] = dd[2] + turnDmg + diff.enemyDmgMod + Math.floor((effectiveFloor - 1) * 0.5) + cycleDmg;
    if (dd[2] < 0) dd[2] = 0;
    var finalHp = Math.round(tmpl.hp * scale * turnScale * diff.enemyHpMul * cycleMul);
    // 스킬 쿨다운 초기화
    var eSkills = tmpl.skills ? tmpl.skills.slice() : [];
    var eSkillCd = {};
    for (var si = 0; si < eSkills.length; si++) eSkillCd[eSkills[si]] = 0;
    return {
        key:key, name:tmpl.name, icon:tmpl.icon,
        hp:finalHp, maxHp:finalHp,
        ac:tmpl.ac + Math.floor((effectiveFloor-1)*0.20) + turnAC + diff.enemyAcMod + cycleAC,
        hitMod:tmpl.hitMod + Math.floor((effectiveFloor-1)*0.4) + turnHit + diff.enemyHitMod + cycleHit,
        dmgDice:dd,
        exp:Math.round(tmpl.exp*scale*diff.expMul), gold:Math.round(tmpl.gold*scale*diff.goldMul),
        boss:tmpl.boss, elite:tmpl.elite, _canRevive:(key==="orcWarlord"||key==="demonPrince"), abilities:ab,
        tags: tmpl.tags ? tmpl.tags.slice() : [],
        shield: tmpl.shield ? Math.round(tmpl.shield * scale * turnScale * diff.enemyHpMul * cycleMul) : 0,
        _battleTurn:0,
        _dmgScale: turnDmgScale,             // 글로벌 턴 비례 피해 배율
        modifier: null,  // 수식어 (applyEnemyModifier에서 부여)
        skills: eSkills,
        _skillCooldowns: eSkillCd,
        _atkBuff: 0, _atkBuffTurns: 0,     // 공격 버프
        _acBuff: 0, _acBuffTurns: 0,        // AC 버프
        _hitBuff: 0, _hitBuffTurns: 0,      // 명중 버프
        _portraitVariant: (key === "vampire" && Math.random() < 0.5) ? "m" : "f",  // 뱀파이어 남/녀 스폰 시 결정
    };
}

// ═══════════════════════════════════════
//  몬스터 수식어 시스템
