    _lastDesperateBonus = false;
    // 혼돈 친화: 크리 확률 +15% (D20 결과 17+ 도 크리로 취급)
    // 사냥꾼: 전투 첫 공격 확정 크리
    if (hasPassive("hawkEye") && !playerBuff._hawkEyeUsed && !r.critFail) {
        playerBuff._hawkEyeUsed = true;
        r.crit = true; r.hit = true;
        addLog("🦅 매의 눈! 선제 크리티컬!", "crit");
    }
    if (hasPassive("chaosAffinity") && !r.crit && !r.critFail && r.roll >= 17) {
        r.crit = true; r.hit = true;
    }
