    var desp = (desperateBonus !== undefined) ? desperateBonus : _lastDesperateBonus;
    if (desp) { total = Math.round(total * 1.5); _lastDesperateBonus = false; addLog("🎯 궁지의 일격! 낮은명중 스킬 피해 +50%!", "buff"); }
