            // 패시브: readyBattle — 전투 시작 시 현재HP 50% 보호막
            if (typeof hasPassive === "function" && hasPassive("readyBattle")) { var rbShield = Math.round(player.hp * 0.3); rbShield = addShieldToPlayer(rbShield); addLog("🛡️ 준비된 전투! 보호막 +" + rbShield, "buff"); }
            if (typeof hasPassive === "function" && hasPassive("sacredShield")) { var ssShield = Math.round(player.maxHp * 0.2); ssShield = addShieldToPlayer(ssShield); addLog("🛡️ 성스러운 방패! 보호막 +" + ssShield, "buff"); }
