            var rewards = [];
            var usedPassives = {};

            // 슬롯 타입 결정: 첫 번째는 반드시 패시브, 나머지 2개는 랜덤
            var slotTypes = ["passive"];
            var typePool = ["passive","passive","gold","gold","stat","stat","exp","exp"];
