// ─── 축복 보상 선택 (3선택지: 패시브/골드/능력치) ───
function pickBlessingReward(index) {
    if (!gameState || !gameState.blessingRewards) return;
    startEventLogCapture();
    var reward = gameState.blessingRewards[index];
    if (!reward) return;

    if (reward.type === "passive") {
        if (!player.passives) player.passives = [];
        if (player.passives.indexOf(reward.key) >= 0) { showToast("이미 보유한 패시브!"); return; }
        player.passives.push(reward.key);
        var pDef = PASSIVE_DEFS[reward.key];
        var pIcon = pDef ? pDef.icon : "🌟";
        addLog("🌟 새 패시브 획득! " + pIcon + " " + reward.name + " — " + reward.desc, "level");
    } else if (reward.type === "gold") {
        player.gold += reward.amount;
        addLog("💰 축복의 금화! +" + reward.amount + "G (총 " + player.gold + "G)", "heal");
    } else if (reward.type === "exp") {
        player.exp += reward.amount;
        addLog("📖 축복의 경험! +" + reward.amount + " EXP", "level");
        checkLevelUp();
    } else if (reward.type === "stat") {
        player.abilities[reward.stat] = (player.abilities[reward.stat] || 10) + reward.amount;
        addLog("⬆️ 축복의 힘! " + reward.name + " (현재 " + player.abilities[reward.stat] + ")", "level");
    }

    playBlessSound();
    gameState.blessingRewards = null;
    gameState.blessingChoices = null;
    gameState.passiveChoices = null;
    saveEventLog(); saveAll(); render();
}

