            if(player.isDefending)rawDmg=Math.max(1,Math.round(rawDmg*0.4));if(playerBuff._riposte)rawDmg=Math.max(1,Math.round(rawDmg*0.5));var dr=damageReduction();var dmg=Math.max(1,rawDmg-dr);_enemyCritFlag=r.crit;applyDamageToPlayer(dmg);applyPoisonOnHit();var drStr=dr>0?" (DR-"+dr+")":"";if(r.crit){addLog(currentEnemy.icon+" 치명타!! [D20→20] "+currentEnemy.dmgDice[0]+"d"+currentEnemy.dmgDice[1]+"×2→"+rawDmg+drStr+"=💥"+dmg,"crit-enemy");}else{addLog(currentEnemy.icon+" "+currentEnemy.name+" [D20→"+r.roll+"] "+currentEnemy.dmgDice[0]+"d"+currentEnemy.dmgDice[1]+(enrageDmg>0?"+"+enrageDmg:"")+"→"+rawDmg+drStr+"="+dmg+" 피해","enemy");}playHitSound();
