    if (hasMutation("regenerator") && player && player.hp < player.maxHp) { var _rgH=Math.max(1,Math.round(player.maxHp*0.05));player.hp=Math.min(player.maxHp,player.hp+_rgH); }
    // 소환수 자동타격
