//  UI 생성 (API 3.0: iframe 컨테이너)
// ═══════════════════════════════════════
function createUI() {
    injectStyles();
    if(!document.getElementById(RPG_UI_ID)){
        var win=document.createElement("div");win.id=RPG_UI_ID;
        win.innerHTML='<div class="rpg-header" id="rpg-drag-header">'+
            (function(){var _hft=(gameState&&gameState.floor&&gameState.running!==false)?getFloorTheme(gameState.floor):null;return '<div class="rpg-header-title">⚔️ 리스라이크 RPG'+(_hft?' <span style="font-size:10px;color:'+_hft.color+';">'+_hft.icon+' '+gameState.floor+'F</span>':' <span style="font-size:10px;opacity:0.5;">v7</span>')+'</div>';})()+
            '<div style="display:flex;gap:6px;">'+
            '<button class="rpg-header-btn" id="rpg-scale-btn" title="UI 확대">'+(_uiScale===3?'🖥️':_uiScale===2?'🔍':'🔎')+'</button>'+
            '<button class="rpg-header-btn" id="rpg-grave-btn" title="묘지">🪦</button>'+
            '<button class="rpg-header-btn" id="rpg-codex-btn" title="도감">📖</button>'+
            '<button class="rpg-header-btn" id="rpg-slot-btn" title="캐릭터 슬롯">📂</button>'+
            '<button class="rpg-header-btn" id="rpg-home-btn" title="메인 화면">🏠</button>'+
            '<button class="rpg-header-btn" id="rpg-new-btn" title="새 게임">🔄</button>'+
            '<button class="rpg-header-btn" id="rpg-close-btn">✕</button>'+
            '</div></div><div class="rpg-body" id="rpg-body"></div>';
        document.body.appendChild(win);
        win.querySelector("#rpg-close-btn").addEventListener("click", async function(){
            win.classList.add("hidden");
            isWindowVisible = false;
            await lsSet(KEY_VISIBLE, "false");
            if (_hasRisu) await Risuai.hideContainer();
        });
        win.querySelector("#rpg-scale-btn").addEventListener("click",function(){
            if (_uiScale === 1) _uiScale = 2;
            else if (_uiScale === 2) _uiScale = 3;
            else _uiScale = 1;
            _applyScale();
            render();
        });
        win.querySelector("#rpg-grave-btn").addEventListener("click",function(){ window.rpg_openGraveyard(); });
        var _codexBtn = win.querySelector("#rpg-codex-btn");
        if (_codexBtn) _codexBtn.addEventListener("click",function(){ window.rpg_openCodex(); });
        win.querySelector("#rpg-slot-btn").addEventListener("click",function(){ window.rpg_openSlotMenu(); });
        win.querySelector("#rpg-home-btn").addEventListener("click",function(){ window.rpg_goHome(); });
        win.querySelector("#rpg-new-btn").addEventListener("click",function(){ window.rpg_showNewGameConfirm(); });
        // iframe 환경에서는 드래그 불필요 (fullscreen)
    }
    // ─── 우측 상단 토글 버튼 제거됨 (UI 겹침 방지) ───
    render();
}

