window.rpg_toggleInventory = function(){ showInventoryTab = !showInventoryTab; showPassiveTab = false; _selectedInvIdx = -1; render(); };
window.rpg_toggleAutocast = function(){
    _autoFreeTurn = !_autoFreeTurn;
    showToast("⚡ 자동 시전 " + (_autoFreeTurn ? "ON" : "OFF"));
    render();

};
