var _showNewGameConfirm = false;
var _autoFreeTurn = false;
var _autoBookBuy = false;
var _uiScale = 1;
var _scaleWrapper = null;
function _applyScale() {
    var container = document.getElementById(RPG_UI_ID);
    if (!container) return;
    container.style.zoom = "";
    container.style.maxHeight = "";
    container.style.height = "";
    var body = container.querySelector(".rpg-body");
    if (body) { body.style.maxHeight = ""; }
    var ss = document.getElementById("rpg-scale-style");
    if (ss) ss.textContent = "";

    if (_uiScale <= 1) return;

    var zoomVal = _uiScale === 2 ? 1.5 : 2.0;
    container.style.zoom = zoomVal;
    // 컨테이너 높이를 zoom 고려해서 재계산 (position:fixed 유지)
    // zoom이 적용되면 100vh도 zoom 배율만큼 줄어들어 보이므로 보정
    var vh = window.innerHeight || 800;
    var adjustedH = Math.floor(vh / zoomVal) - 40; // zoom 보정된 높이
    container.style.maxHeight = adjustedH + "px";
    container.style.height = adjustedH + "px";
    // rpg-body도 남은 높이 꽉 채우도록
    if (body) {
        body.style.maxHeight = "none";
        body.style.flex = "1";
        body.style.overflowY = "auto";
    }
}
function _scaleUpdateHeight() {}

/** 자동 시전: 쿨 안 걸린 freeTurn 스킬을 순서대로 시전 */
function autocastFreeTurnSkills() {
    if (!_autoFreeTurn || !player || !gameState || !currentEnemy || currentEnemy.hp <= 0) return;
    if (battlePhase !== "playerTurn") return;
    var cast = false;
    for (var i = 0; i < player.skills.length; i++) {
        var sk = player.skills[i];
        var def = SKILL_DEFS[sk];
        if (!def || !def.freeTurn) continue;
        var cd = (skillCooldowns[sk] && skillCooldowns[sk] > 0) ? skillCooldowns[sk] : 0;
        if (cd > 0) continue;
        // 회복 스킬은 HP 풀이면 스킵
        if (def.tags && def.tags.indexOf("회복") >= 0 && player.hp >= player.maxHp) continue;
        addLog("⚡ 자동시전: " + def.icon + " " + def.name, "info");
        playerAttack(sk);
        cast = true;
        return; // 한 번에 하나씩 (재귀적으로 다음 것도 실행됨)
    }
}
window.rpg_newGame     = function(){ startNewGame(); };
window.rpg_showNewGameConfirm = function(){
    _showNewGameConfirm = true; render();
};
window.rpg_confirmNewGame = async function(){
    _showNewGameConfirm = false;
    // 전투 중이면 현재 슬롯 삭제 (게임 포기)
    if (_activeSlot > 0) {
        try {
            if (_hasRisu) { await Risuai.setArgument(slotKey(_activeSlot), ""); }
            else { localStorage.removeItem(slotKey(_activeSlot)); }
        } catch(e) { console.warn("[RPG] error:", e); }
    }
    _activeSlot = 0;
    startNewGame();
};
window.rpg_cancelNewGame = function(){ _showNewGameConfirm = false; render(); };
window.rpg_selectDifficulty = function(lv){ selectDifficulty(lv); };
window.rpg_continue    = async function(){
    // 모든 오버레이 닫기
    _slotMenuOpen = false; _slotFullPickMode = false; _showNewGameConfirm = false;
    _codexOpen = false; _graveyardOpen = false;
    _achievementOpen = false; _statsOpen = false;
    _transferMode = null; _transferCode = null;
    if(await loadAll()){
        if(gameState.difficulty) gameDifficulty = gameState.difficulty;
        if(gameState.phase==="battle") {
            gameState.phase = "chooseDoor";
            addLog("⚠️ 전투 중 중단됨 — 문 선택으로 돌아갑니다.", "info");
        }
        if(gameState.phase==="chooseDoor" && !gameState.doorChoices) gameState.doorChoices=generateDoorChoices();
        if(!player.equipment) player.equipment = [];
        if(!Array.isArray(player.equipment)) {
            var arr = []; for(var k in player.equipment){ if(player.equipment[k]) arr.push(player.equipment[k]); }
            player.equipment = arr;
        }
        if(!player.passives) player.passives = [];
        currentEnemy = null; battlePhase = "";
        render();
    }
};
window.rpg_legendaryBless = function(idx) {
    if (!gameState._legendaryBlessingChoices) return;
    var item = gameState._legendaryBlessingChoices[idx];
    if (!item) return;
    startEventLogCapture();
    addEquipToInventory(item);
    var _lbRC = {legendary:'#ffd700',mythic:'#ff6b6b'}[item.rarity]||'#ffd700';
    var _lbPortrait = (EQUIP_PORTRAITS && EQUIP_PORTRAITS[item.id]) ? '<img src="'+EQUIP_PORTRAITS[item.id]+'" width="48" height="48" style="border-radius:8px;image-rendering:pixelated;border:2px solid rgba(255,215,0,0.5);vertical-align:middle;margin-right:6px;" />' : '';
    addLog("👑 제단의 빛이 선택한 유물에 집중된다...", "level");
    addLog("✅ " + _lbPortrait + "<span style='color:"+_lbRC+";font-weight:bold;'>"+item.icon+" "+item.name+" ("+EQUIP_RARITIES[item.rarity].name+")</span> 획득!", "level");
    // 스탯 보너스 표시
    var _lbBonuses = [];
    if (item.bonuses) { for (var _bk in item.bonuses) { if (item.bonuses[_bk]) _lbBonuses.push(_bk.toUpperCase()+" +"+item.bonuses[_bk]); } }
    if (_lbBonuses.length > 0) addLog("📊 " + _lbBonuses.join(", "), "info");
    if (item.passive && PASSIVE_DEFS[item.passive]) addLog("🌟 전설 패시브 각성! " + PASSIVE_DEFS[item.passive].icon + " " + PASSIVE_DEFS[item.passive].name + " — " + PASSIVE_DEFS[item.passive].desc, "buff");
    addLog("👑 전설의 제단이 빛을 잃고 침묵한다...", "info");
    gameState._legendaryBlessingChoices = null;
    saveEventLog(); saveAll(); render();
};
