// ─── 퀘스트 선택 핸들러 ───
window.rpg_questChoice = function(choice) {
    var q = gameState.quest;
    var result = { title:"", dialogue:"", effects:[], icon:"📜" };

    switch(choice) {
        // ── 리리스 ──
        case "dg_help":
            var hasPotion = false;
            if (player.potionInventory) { for (var pk in player.potionInventory) { if (player.potionInventory[pk] > 0) { player.potionInventory[pk]--; hasPotion = true; break; } } }
            if (!hasPotion && player.hp > Math.round(player.maxHp * 0.3)) { player.hp -= Math.round(player.maxHp * 0.2); hasPotion = true; }
            if (!hasPotion) { showToast("포션도 없고 HP도 부족합니다!"); return; }
            startQuest("lilith");
            // 리리스 즉시 전투지원 시작 (20% 기본)
            gameState.ally = { id:"lilith", name:"리리스", icon:"🦇", triggerRate:0.20, effect:"damage", power:8, dialogue:["내가 도와줄게!","마족의 힘!","같이 싸우자!"] };
            result.icon = "🦇"; result._lilithPortrait = "lilith_default"; result.title = "리리스와의 만남";
            result.dialogue = "고마워... 이름이... 리리스야... 같이 가도 될까?";
            result.effects.push("📜 퀘스트 시작: 마족 소녀 리리스");
            result.effects.push("💊 포션 1개 소모");
            break;
        case "dg_ignore":
            gameState._questPending = null;
            if (!gameState.questsCompleted) gameState.questsCompleted = []; if (gameState.questsCompleted.indexOf("lilith") < 0) gameState.questsCompleted.push("lilith");
            result.icon = "🚶"; result._lilithPortrait = "lilith_scared"; result.title = "지나침";
            result.dialogue = "...";
            result.effects.push("소녀를 지나쳤다.");
            break;
        case "dg_share":
            q.choices.kindness++;
            var halfGold = Math.round((gameState._questTreasureGold || 80) / 2);
            player.gold += halfGold;
            result.icon = "🦇"; result._lilithPortrait = "lilith_cling"; result.title = "보물 분배";
            result.dialogue = "고마워! 역시 좋은 사람이야!";
            result.effects.push("💰 +" + halfGold + "G 획득");
            result.effects.push("💜 호감도 UP ♥");
            if (gameState.ally && gameState.ally.id === "lilith") { gameState.ally.triggerRate = Math.min(0.35, gameState.ally.triggerRate + 0.05); result.effects.push("🦇 리리스 지원 확률 +" + Math.round(gameState.ally.triggerRate*100) + "%"); }
            advanceQuest();
            break;
        case "dg_hoard":
            q.choices.greed++;
            var fullGold = (gameState._questTreasureGold || 80) + 500;
            player.gold += fullGold;
            // 전설 장비 드롭
            var _hoardPool = EQUIP_DB.filter(function(e){ return e.rarity === "legendary"; });
            if (_hoardPool.length > 0) {
                var _hoardItem = JSON.parse(JSON.stringify(pick(_hoardPool)));
                addEquipToInventory(_hoardItem);
                result.effects.push("🏆 전설급 장비: " + _hoardItem.icon + " " + _hoardItem.name);
            }
            result.icon = "🦇"; result._lilithPortrait = "lilith_greed1"; result.title = "보물 독식";
            result.dialogue = "...그래. 네가 더 필요하겠지.";
            result.effects.push("💰 +" + fullGold + "G 획득");
            result.effects.push("💔 호감도 DOWN ♡");
            advanceQuest();
            break;
        case "dg_protect":
            q.choices.kindness++;
            var protDmg = Math.max(1, Math.round(player.maxHp * 0.2));
            player.hp = Math.max(1, player.hp - protDmg);
            result.icon = "🦇"; result._lilithPortrait = "lilith_grateful"; result.title = "리리스를 감쌌다";
            result.dialogue = "왜... 나 같은 마족을 위해...";
            result.effects.push("❤️ HP -" + protDmg);
            result.effects.push("💜 호감도 UP ♥♥");
            if (gameState.ally && gameState.ally.id === "lilith") { gameState.ally.triggerRate = Math.min(0.35, gameState.ally.triggerRate + 0.05); result.effects.push("🦇 리리스 지원 확률 +" + Math.round(gameState.ally.triggerRate*100) + "%"); }
            advanceQuest();
            break;
        case "dg_bait":
            q.choices.greed++;
            playerBuff._allyBait = true;
            // 전설 장비 추가 드롭
            var _baitPool = EQUIP_DB.filter(function(e){ return e.rarity === "legendary"; });
            if (_baitPool.length > 0) {
                var _baitItem = JSON.parse(JSON.stringify(pick(_baitPool)));
                addEquipToInventory(_baitItem);
                result.effects.push("🏆 전설급 장비: " + _baitItem.icon + " " + _baitItem.name);
            }
            player.gold += 500;
            result.icon = "🦇"; result._lilithPortrait = "lilith_hurt1"; result.title = "미끼로 내세움";
            result.dialogue = "...!!";
            result.effects.push("💰 +500G 획득");
            result.effects.push("🎯 다음 전투: 적 3턴 스턴");
            result.effects.push("💔 호감도 DOWN ♡♡");
            advanceQuest();
            break;
        case "dg_marry":
            var _lilK = q.choices.kindness || 0;
            if (_lilK >= 2) {
                // 호감도 높음 → 결혼 히든 엔딩
                q.flags.ending = "marry";
                completeQuest({
                    ally: { id:"lilith", name:"리리스", icon:"🦇", triggerRate:0.30, effect:"damage", power:10, dialogue:["당신을 지킬게!","마족의 힘을 보여줄게!","같이 싸우자, 영원히!"] }
                });
                unlockAchievement("demon_lord");
                result.icon = "💜"; result._lilithPortrait = "lilith_wedding"; result.title = "영원히 함께";
                result.dialogue = "정말...? 나 같은 마족이랑...? ...고마워. 영원히 함께야.";
                result.effects.push("🤝 동료 획득: 🦇 리리스 (30% 전투 지원)");
                result.effects.push("🏆 업적: 마왕의 길");
                result.effects.push("👑 10층 히든 엔딩 해금");
            } else {
                // 호감도 낮음 → 이별 루트
                q.flags.ending = "farewell_reject";
                playerBuff._allyExpBuff = 3;
                completeQuest(null);
                result.icon = "🦇"; result._lilithPortrait = "lilith_farewell"; result.title = "닿을 수 없는 마음";
                result.dialogue = "함께하고 싶었지만... 나는 마족이야. 네 곁에 있으면 안 되는 존재야.\n...고마웠어. 정말로.";
                result.effects.push("💔 호감도가 부족하여 리리스가 떠납니다");
                result.effects.push("📜 리리스의 편지 (3전투 EXP 1.5배)");
            }
            break;
        case "dg_betray":
            q.flags.ending = "betray";
            var _allStats = ["str","dex","con","int","wis","cha"];
            _allStats.forEach(function(s){ player.abilities[s] += 2; });
            recalcPlayerStats();
            // 리리스 동료 제거
            if (gameState.ally && gameState.ally.id === "lilith") gameState.ally = null;
            completeQuest(null);
            unlockAchievement("betrayer");
            // 보스전 전환 — 비극적 이벤트 전투
            currentEnemy = { key:"lilith_boss", name:"절망의 리리스", icon:"🦇", hp:1000, maxHp:1000, ac:16, hitMod:8, dmgDice:[2,8,5], exp:500, gold:300, boss:false, elite:false, tags:["악마","흡혈"], abilities:{str:14,dex:18,con:14,int:14,wis:12,cha:20}, skills:[], _skillCooldowns:{}, _battleTurn:0, shield:0,
                _lilithBoss: true, _dmgCap: 200, _lastDialogueHp: 1000
            };
            battlePhase = "playerTurn";
            gameState.phase = "battle";
            result.icon = "🗡️"; result._lilithPortrait = "lilith_boss"; result.title = "배신";
            result.dialogue = "...배신...이었어...?";
            result.effects.push("⚔️ 전 능력치 +2 (영구)");
            result.effects.push("⚔️ 리리스와의 전투 시작!");
            result.effects.push("🔴 승리 시 신화 장비 획득!");
            result.effects.push("🏆 업적: 배신자");
            break;
        case "dg_farewell":
            q.flags.ending = "farewell";
            playerBuff._allyExpBuff = 3;
            completeQuest(null);
            result.icon = "🦇"; result._lilithPortrait = "lilith_farewell"; result.title = "이별";
            result.dialogue = "...잘 지내. 고마웠어.";
            result.effects.push("📜 리리스의 편지 (3전투 EXP 1.5배)");
            break;

        // ── 떠도는 영혼 ──
        case "ws_accept":
            startQuest("ghost_relic");
            result.icon = "👻"; result.title = "영혼의 부탁";
            result.dialogue = "고마워... 꼭... 찾아줘...";
            result.effects.push("📜 퀘스트 시작: 떠도는 영혼");
            result.effects.push("🔍 유물 조각 3개를 찾아야 한다");
            break;
        case "ws_decline":
            gameState._questPending = null;
            result.icon = "👻"; result.title = "무시";
            result.dialogue = "......";
            result.effects.push("영혼이 조용히 사라진다...");
            break;
        case "ws_free":
            var _wsStats = ["str","dex","con","int","wis","cha"];
            _wsStats.forEach(function(s){ player.abilities[s] += 1; });
            recalcPlayerStats();
            completeQuest({
                ally: { id:"guardian_spirit", name:"수호령", icon:"👻", triggerRate:0.20, effect:"shield", power:30, dialogue:["지켜줄게...","위험해!","조심해..."] }
            });
            unlockAchievement("soul_liberator");
            result.icon = "🕊️"; result.title = "영혼 성불";
            result.dialogue = "고마워... 축복을 남기고 갈게...";
            result.effects.push("✨ 전 능력치 +1 (영구)");
            result.effects.push("🤝 동료 획득: 👻 수호령 (20% 피해 감소)");
            result.effects.push("🏆 업적: 영혼 해방자");
            break;
        case "ws_take":
            var legPool = EQUIP_DB.filter(function(e){return e.rarity==="legendary";});
            if (legPool.length > 0) {
                var eq = JSON.parse(JSON.stringify(pick(legPool)));
                addEquipToInventory(eq);
                result.effects.push("🏆 전설 장비: " + eq.icon + " " + eq.name);
            }
            completeQuest(null);
            result.icon = "💀"; result.title = "유물 탈취";
            result.dialogue = "...왜...";
            break;

        // ── 비밀 상인 ──
        case "sm_50": case "sm_100": case "sm_200":
            var amt = parseInt(choice.split("_")[1]);
            if (player.gold < amt) { showToast("골드 부족!"); return; }
            player.gold -= amt;
            startQuest("shady_deal");
            gameState.quest.choices.invested = amt;
            result.icon = "🏪"; result.title = "투자 완료";
            result.dialogue = "좋은 선택이야! 기다려봐!";
            result.effects.push("💰 -" + amt + "G 투자");
            result.effects.push("📜 퀘스트 시작: 비밀 상인");
            break;
        case "sm_decline":
            gameState._questPending = null;
            result.icon = "🏪"; result.title = "거절";
            result.dialogue = "아쉽군... 다음에 보자.";
            break;
        case "sm_add100": case "sm_add200":
            var addAmt = parseInt(choice.split("add")[1]);
            if (!q || player.gold < addAmt) { showToast("골드 부족!"); return; }
            player.gold -= addAmt;
            q.choices.invested += addAmt;
            result.icon = "🏪"; result.title = "추가 투자";
            result.dialogue = "더 넣는 거야? 좋아좋아!";
            result.effects.push("💰 -" + addAmt + "G 추가 (총 " + q.choices.invested + "G)");
            advanceQuest();
            break;
        case "sm_stop":
            result.icon = "🏪"; result.title = "투자 중단";
            result.dialogue = "알겠어, 나중에 찾아올게!";
            advanceQuest();
            break;

        // ── 고대 비문 ──
        case "at_accept":
            startQuest("rune_decode");
            var _atChk1 = abilityCheck("int", 12);
            if (_atChk1.success) {
                gameState.quest.choices.success = (gameState.quest.choices.success||0) + 1;
                player.exp += 25;
                result.effects.push("📖 첫 번째 비문 해독 성공!");
                result.effects.push("📖 +25 EXP");
            } else {
                gameState.quest.choices.fail = (gameState.quest.choices.fail||0) + 1;
                var _atDmg1 = Math.max(1, Math.round(player.maxHp * 0.08));
                player.hp = Math.max(1, player.hp - _atDmg1);
                result.effects.push("💥 해독 실패... 함정! HP -" + _atDmg1);
            }
            result.icon = "📜"; result.title = "비문 해독";
            result.dialogue = "고대의 문자가 빛을 발한다...";
            result.effects.push("📜 퀘스트 시작: 고대 비문");
            break;
        case "at_decline":
            gameState._questPending = null;
            result.icon = "📜"; result.title = "무시";
            result.dialogue = "";
            result.effects.push("비문을 무시하고 지나쳤다.");
            break;

        // ── 복수자 ──
        case "av_accept":
            startQuest("avenger");
            result.icon = "⚔️"; result.title = "의뢰 수락";
            result.dialogue = "좋아! 첫 번째 녀석은 금방 나타날 거야.";
            result.effects.push("📜 퀘스트 시작: 복수자");
            result.effects.push("⚔️ 현상금 몬스터 3마리 처치 의뢰");
            break;
        case "av_decline":
            gameState._questPending = null;
            result.icon = "⚔️"; result.title = "거절";
            result.dialogue = "...겁쟁이군.";
            break;
    }

    // 결과 화면 저장 → 렌더
    gameState._questResult = result;
    if (player.hp <= 0) { handleDefeat(); return; }
    saveAll(); render();
};

