window.rpg_usePotion   = function(key){
    if(!player) return;
    migratePotions();
    if(!key) {
        var order = ["potion_s","potion_m","potion_l","potion_x","potion_full"];
        for(var i=0;i<order.length;i++){
            if(player.potionInventory[order[i]] && player.potionInventory[order[i]]>0){ key=order[i]; break; }
        }
    }
    if(!key){ showToast("포션 없음!"); return; }
    if(battlePhase==="playerTurn") { window.rpg_action(key); return; }
};
window.rpg_usePotionAnytime = function(key){
    if(!player||player.hp>=player.maxHp) return;
    migratePotions();
    if(!key) {
        var order = ["potion_s","potion_m","potion_l","potion_x","potion_full"];
        for(var i=0;i<order.length;i++){
            if(player.potionInventory[order[i]] && player.potionInventory[order[i]]>0){ key=order[i]; break; }
        }
    }
    if(!key){ showToast("포션 없음!"); return; }
    var pDef = POTION_DEFS[key]; if(!pDef) return;
    var heal = usePotionByKey(key);
    if(heal<=0){ showToast("해당 포션 없음!"); return; }
    addLog(pDef.icon+" "+pDef.name+" 사용! → HP+"+heal+" ("+player.hp+"/"+player.maxHp+")","heal");
    playPotionSound(); saveAll(); render();
};
window.rpg_action      = function(action){
    try {
    // 이전 상태 저장 (이펙트 판별용)
    var _prevEnemyHp = currentEnemy ? currentEnemy.hp : 0;
    var _prevEnemyShield = currentEnemy ? (currentEnemy.shield||0) : 0;
    var _prevPlayerHp = player ? player.hp : 0;
    var _prevShield = player ? (player.shield||0) : 0;
    playerAttack(action);
    var noShake=["defend","evasion","smokeBomb","arcaneShield","secondWind","blessedHeal","hunterMark","bloodPact","layOnHands","divineBarrier","frenzy","inspireSong","healingMelody","royalCommand","summonGuard","entangle","seduce","wardOfLight","timeWarp","soulShield","mutagen","ironBody"];
    if(action.indexOf("potion_")===0) noShake.push(action);
    // 이펙트 판별
    var _fxDelay = 50; // 기본 렌더 딜레이
    if (currentEnemy && noShake.indexOf(action)<0) {
        if (currentEnemy.hp <= 0) {
            // handleVictory에서 사망 이펙트 처리
        } else if (currentEnemy.hp < _prevEnemyHp || (currentEnemy.shield||0) < _prevEnemyShield) {
            var _elemType = _getElementPopupType(action, _lastCritFlag);
            var _dmgAmt = (_prevEnemyHp - currentEnemy.hp) + (_prevEnemyShield - (currentEnemy.shield||0));
            var _elemIcon = _elemIcons[_elemType] || "";
            if (_lastCritFlag) { _fxDelay = 500; fxEnemyCritElement(action); showDmgPopup(_elemIcon+_dmgAmt+'!', _elemType); }
            else { _fxDelay = 350; fxEnemyHitElement(action); showDmgPopup(_elemIcon+'-'+_dmgAmt, _elemType); }
        } else if (currentEnemy.hp === _prevEnemyHp && noShake.indexOf(action)<0) {
            _fxDelay = 400; fxEnemyMiss(); showDmgPopup('MISS', 'miss');
        }
    }
    // 회복/버프/보호막 이펙트
    if (player) {
        if (player.hp > _prevPlayerHp) { fxPlayerHeal(); showDmgPopup('+' + (player.hp - _prevPlayerHp), 'heal', '.rpg-portrait-sm'); }
        if ((player.shield||0) > _prevShield) fxPlayerShield();
        if (["defend","arcaneShield","secondWind","blessedHeal","layOnHands","divineBarrier","inspireSong","healingMelody","seduce","wardOfLight","mutagen","ironBody","soulShield"].indexOf(action)>=0) fxPlayerBuff();
    }
    setTimeout(function(){render();}, _fxDelay);
    } catch(e) { console.error("[RPG] rpg_action error:", e.message, e.stack); }
};
