window.rpg_toggleAutoBook = function(){
    _autoBookBuy = !_autoBookBuy;
    // ON으로 바꿨을 때 즉시 구매 시도
    if (_autoBookBuy && gameState && gameState.merchantOffers) {
        for (var _ti = 0; _ti < gameState.merchantOffers.length; _ti++) {
            var _to = gameState.merchantOffers[_ti];
            if (_to.type === "statBook" && !_to.sold && player.gold >= _to.cost) {
                buyMerchantItem(_ti);
                return;
            }
        }
    }
    render();
};
window.rpg_gamble = function(size){
    if (!gameState || gameState.gamblingState !== "pending") return;
    var bet = gameState.gamblingBet || 0;
    var amount = (size === "big") ? bet : Math.min(bet, Math.round(bet * 0.3));
    if (player.gold < amount) { showToast("골드 부족!"); return; }
    player.gold -= amount;
    var roll = Math.random();
    if (roll < 0.15) {
        // 대박 (15%): 3배
        var win = amount * 3;
        player.gold += win;
        addLog("🎰 대박!! " + amount + "G → " + win + "G! (+" + (win-amount) + "G)", "level");
        playCritSound();
    } else if (roll < 0.45) {
        // 이득 (30%): 1.5배
        var win = Math.round(amount * 1.5);
        player.gold += win;
        addLog("🎰 이겼다! " + amount + "G → " + win + "G", "win");
        playGoldSound();
    } else if (roll < 0.70) {
        // 본전 (25%)
        player.gold += amount;
        addLog("🎰 본전... " + amount + "G 환불", "info");
    } else {
        // 잃음 (30%)
        addLog("🎰 졌다... " + amount + "G 잃음!", "enemy");
        playDangerSound();
    }
    gameState.gamblingState = "done";
    saveAll(); render();
};
